mapper.select:
SELECT * FROM khuyen_mai WHERE UPPER(TRIM(ma_code)) = UPPER(TRIM(#{maCode}))
AND ma != #{maLoaiTru}
LIMIT 1

SELECT COUNT(*) FROM khuyen_mai
WHERE hoat_dong = 1 AND ngay_bat_dau <= #{luc} AND ngay_ket_thuc >= #{luc}
AND (gioi_han_so_lan IS NULL OR so_lan_da_dung < gioi_han_so_lan)

mapper.update:
UPDATE khuyen_mai SET ma_code = #{maCode}, tieu_de = #{tieuDe}, phan_tram_giam = #{phanTramGiam},
    so_tien_giam_toi_da = #{soTienGiamToiDa}, ngay_bat_dau = #{ngayBatDau}, ngay_ket_thuc = #{ngayKetThuc},
    gioi_han_so_lan = #{soLanToiDa}, so_lan_da_dung = #{soLanDaDung}, hoat_dong = #{hoatDong}
WHERE ma = #{ma}
